public class UserService
{
    private const string CODE = "secret";
    private int callCount = 0;

    public string GetCode()
    {
        callCount++;
        return CODE;
    }

    public string GetName() // Compliant: clear intent, delegates to GetCode
    {
        return GetCode();
    }
}

public class Calculator
{
    public int AddNumbers(int a, int b) // Compliant: unique implementation
    {
        return PerformCalculation(a, b, "Addition");
    }

    public int SumValues(int x, int y) // Compliant: delegates to common method
    {
        return PerformCalculation(x, y, "Sum");
    }

    private int PerformCalculation(int a, int b, string operation)
    {
        int result = a + b;
        Console.WriteLine($"{operation} Result: {result}");
        return result;
    }
}
